export function binarySearchFirstLastPosition(values: number[], target: number): [number, number] {
	const findFirst = (): number => {
		let low = 0;
		let high = values.length - 1;
		let first = -1;
		while (low <= high) {
			const mid = Math.floor((low + high) / 2);
			if (values[mid] === target) {
				first = mid;
				high = mid - 1;
			} else if (values[mid] < target) {
				low = mid + 1;
			} else {
				high = mid - 1;
			}
		}
		return first;
	};

	const findLast = (): number => {
		let low = 0;
		let high = values.length - 1;
		let last = -1;
		while (low <= high) {
			const mid = Math.floor((low + high) / 2);
			if (values[mid] === target) {
				last = mid;
				low = mid + 1;
			} else if (values[mid] < target) {
				low = mid + 1;
			} else {
				high = mid - 1;
			}
		}
		return last;
	};

	return [findFirst(), findLast()];
}

