export function unionFindConnectedComponentsOnline(n: number, operations: readonly (readonly [number, number])[]): number[] {
	const parent = new Int32Array(n);
	const rank = new Int32Array(n);
	for (let i = 0; i < n; i++) {
		parent[i] = i;
		rank[i] = 0;
	}

	const find = (i: number): number => {
		while (parent[i] !== i) {
			parent[i] = parent[parent[i]];
			i = parent[i];
		}
		return i;
	};

	let components = n;
	const results: number[] = new Array(operations.length);

	for (let i = 0; i < operations.length; i++) {
		const [u, v] = operations[i];
		const rootU = find(u);
		const rootV = find(v);

		if (rootU !== rootV) {
			if (rank[rootU] < rank[rootV]) {
				parent[rootU] = rootV;
			} else if (rank[rootU] > rank[rootV]) {
				parent[rootV] = rootU;
			} else {
				parent[rootU] = rootV;
				rank[rootV]++;
			}
			components--;
		}
		results[i] = components;
	}

	return results;
}

