        const results: number[] = [];

        for (const [u, v] of operations) {
            const rootU = find(u);
            const rootV = find(v);
            if (rootU !== rootV) {
                parent[rootU] = rootV;
                components--;
            }
            results.push(components);
        }

        return results;
