export function validParentheses(input: string): boolean {
	const stack: string[] = [];
	const brackets: Record<string, string> = {
		')': '(',
		']': '[',
		'}': '{',
	};

	for (const char of input) {
		if (char === '(' || char === '[' || char === '{') {
			stack.push(char);
		} else if (char === ')' || char === ']' || char === '}') {
			if (stack.length === 0 || stack.pop() !== brackets[char]) {
				return false;
			}
		}
	}

	return stack.length === 0;
}

